#include <iostream>
#include <string>
#include <vector>
#include <cstring>
#include <cctype>

// The countVowels function, identical to the one in 4795.cpp for testing.
// This driver will NOT call countVowels with nullptr to avoid crashing the test harness.
// The robustness issue (nullptr crash) is demonstrated by running the 4795.cpp main directly.
int countVowels(const char* str) {
    int count = 0;
    // Replicating the bug from the submitted code for consistent testing.
    // No nullptr check here, so if nullptr were passed by a test case, it would crash.
    for (int i = 0; str[i] != '\0'; ++i) {
        char c = std::tolower(static_cast<unsigned char>(str[i]));
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
            count++;
        }
    }
    return count;
}

int main() {
    std::vector<std::pair<const char*, int>> tests = {
        {"Hello World!", 3},
        {"Programming is FUN", 5},
        {"AEIOUaeiou", 10},
        {"Rhythm", 0},
        {"", 0}
    };

    for (const auto& test : tests) {
        char buffer[256]; 
        // Assuming test.first is always a valid C-string for these test cases.
        strcpy(buffer, test.first);

        int result = countVowels(buffer);
        std::cout << "Number of vowels: " << result << std::endl;
    }
    return 0;
}
